import React from 'react';
import { NavLink, Link, useNavigate } from 'react-router-dom';

const Navbar = () => {
  const navigate = useNavigate();
  const token = localStorage.getItem('token');
  const user = JSON.parse(localStorage.getItem('user') || '{}');

  const logout = () => {
    localStorage.clear();
    navigate('/login');
  };

  return (
    <nav className="navbar">
      <Link to="/" className="nav-brand">StormShield</Link>
      <div className="nav-links">
        {token ? (
          <>
            <NavLink to="/" end className={({ isActive }) => isActive ? "nav-item active" : "nav-item"}>Dashboard</NavLink>
            <NavLink to="/shelters" className={({ isActive }) => isActive ? "nav-item active" : "nav-item"}>Shelters</NavLink>
            <NavLink to="/alerts" className={({ isActive }) => isActive ? "nav-item active" : "nav-item"}>Alerts</NavLink>
            <NavLink to="/my-supports" className={({ isActive }) => isActive ? "nav-item active" : "nav-item"}>My Requests</NavLink>
            <NavLink to="/notifications" className={({ isActive }) => isActive ? "nav-item active" : "nav-item"}>Notifications</NavLink>
            {(user.role === 'ADMIN' || user.role === 'RESCUER') && (
              <>
                <NavLink to="/admin/reports" className={({ isActive }) => isActive ? "nav-item admin-link active" : "nav-item admin-link"}>Review Reports</NavLink>
                <NavLink to="/admin/supports" className={({ isActive }) => isActive ? "nav-item admin-link active" : "nav-item admin-link"}>Manage Rescues</NavLink>
              </>
            )}
            <button onClick={logout} className="btn btn-outline" style={{marginLeft: '15px'}}>Logout</button>
          </>
        ) : (
          <>
            <NavLink to="/login" className={({ isActive }) => isActive ? "nav-item active" : "nav-item"}>Login</NavLink>
            <NavLink to="/register" className={({ isActive }) => isActive ? "nav-item active" : "nav-item"}>Register</NavLink>
          </>
        )}
      </div>
    </nav>
  );
};
export default Navbar;
